import QRCode from 'qrcode'

const APP_URL = import.meta.env.VITE_APP_URL || 'https://hcd-certificados.vercel.app'

const LOGO_HCD = "data:image/jpeg;base64,"
const FIRMA_NESTOR = "data:image/png;base64,"
const FIRMA_MIRNA = "data:image/png;base64,"

export async function generarQRBase64(idUnico) {
  const url = `${APP_URL}/verificar/${idUnico}`
  return await QRCode.toDataURL(url, { width: 120, margin: 1, color: { dark: '#000000', light: '#ffffff' } })
}

export function abrirCertificadoParaImprimir({ cert, qrBase64 }) {
  const {
    id_unico, nombre_participante, nombre_curso, lugar, duracion,
    fecha_emision, instructor_nombre, instructor_rfc, director_nombre,
  } = cert

  const fechaFormateada = new Date(fecha_emision).toLocaleDateString('es-MX', {
    day: '2-digit', month: 'long', year: 'numeric'
  })

  const ventana = window.open('', '_blank', 'width=1122,height=794')
  const html = `<!DOCTYPE html>
<html lang="es">
<head>
<meta charset="UTF-8"/>
<title>Certificado ${id_unico}</title>
<link rel="preconnect" href="https://fonts.googleapis.com"/>
<link rel="preconnect" href="https://fonts.gstatic.com" crossorigin/>
<link href="https://fonts.googleapis.com/css2?family=Tangerine:wght@400;700&family=Cinzel:wght@400;500;600&family=Inter:wght@400;600;700&display=swap" rel="stylesheet"/>
<style>
*{margin:0;padding:0;box-sizing:border-box;}
@page{size:A4 landscape;margin:0;}
html,body{width:297mm;height:210mm;overflow:hidden;background:#fff;-webkit-print-color-adjust:exact;print-color-adjust:exact;}
.cert{width:297mm;height:210mm;position:relative;background:#fff;padding:16mm 22mm;display:flex;flex-direction:column;font-family:'Inter',sans-serif;}
.lineas-top{position:absolute;top:14mm;right:22mm;display:flex;flex-direction:column;gap:2.5mm;align-items:flex-end;}
.linea-dec{height:3px;background:#8B1A1A;border-radius:2px;}
.linea-dec.l1{width:90mm;}
.linea-dec.l2{width:70mm;}
.logo-wrap{position:absolute;top:12mm;left:22mm;}
.logo-img{height:20mm;width:auto;object-fit:contain;}
.cuerpo{flex:1;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;padding-top:16mm;}
.empresa-nombre{font-size:17pt;font-weight:700;color:#8B1A1A;margin-bottom:2mm;}
.otorga{font-size:11pt;color:#555;margin-bottom:5mm;}
.nombre{font-family:'Tangerine',cursive;font-weight:700;font-size:54pt;color:#1a1a1a;line-height:1;margin-bottom:9mm;padding:0 10mm;}
.por{font-size:10pt;color:#555;margin-bottom:1.5mm;}
.participar{font-size:13pt;font-weight:700;color:#1a1a1a;margin-bottom:1.5mm;}
.el-curso{font-size:10pt;color:#555;margin-bottom:3mm;}
.curso-nombre{font-family:'Cinzel',serif;font-weight:600;font-size:19pt;color:#1a1a1a;letter-spacing:1.5px;}
.qr-wrap{position:absolute;left:22mm;bottom:16mm;text-align:center;}
.qr-img{width:24mm;height:24mm;}
.qr-label{font-size:6pt;color:#999;margin-top:1mm;}
.inferior{display:flex;flex-direction:column;align-items:center;margin-top:auto;padding-bottom:2mm;}
.firmas{display:flex;gap:16mm;justify-content:center;}
.firma{display:flex;flex-direction:column;align-items:center;width:62mm;}
.firma-img-wrap{height:42mm;display:flex;align-items:flex-end;justify-content:center;width:100%;}
.firma-img-n{height:40mm;width:auto;object-fit:contain;}
.firma-img-m{height:22mm;width:auto;object-fit:contain;}
.firma-nombre{font-size:9.5pt;font-weight:700;color:#1a1a1a;text-align:center;margin-top:1mm;}
.firma-cargo{font-size:8pt;color:#555;margin-top:.5mm;}
.firma-rfc{font-size:7pt;color:#999;margin-top:.5mm;}
.datos{position:absolute;right:22mm;bottom:8mm;display:flex;flex-direction:column;gap:1.5mm;align-items:flex-end;}
.dato-row{display:flex;justify-content:flex-end;align-items:baseline;gap:4mm;}
.dato-label{font-size:8.5pt;color:#666;}
.dato-valor{font-size:9pt;font-weight:700;color:#1a1a1a;text-align:right;}
.pie{position:absolute;bottom:8mm;left:22mm;font-size:7pt;color:#bbb;}
@media print{html,body{width:297mm;height:210mm;}.cert{page-break-after:avoid;page-break-inside:avoid;}}
</style>
</head>
<body>
<div class="cert">
  <div class="logo-wrap"><img src="${LOGO_HCD}" class="logo-img"/></div>
  <div class="lineas-top"><div class="linea-dec l1"></div><div class="linea-dec l2"></div></div>
  <div class="cuerpo">
    <div class="empresa-nombre">Hablando con Datos</div>
    <div class="otorga">Otorga el presente reconocimiento a:</div>
    <div class="nombre">${nombre_participante}</div>
    <div class="por">Por</div>
    <div class="participar">Participar y Aprobar</div>
    <div class="el-curso">el curso:</div>
    <div class="curso-nombre">${nombre_curso}</div>
  </div>
  ${qrBase64 ? `<div class="qr-wrap"><img src="${qrBase64}" class="qr-img"/><div class="qr-label">Verificar autenticidad</div></div>` : ''}
  <div class="inferior">
    <div class="firmas">
      <div class="firma">
        <div class="firma-img-wrap"><img src="${FIRMA_NESTOR}" class="firma-img-n"/></div>
        <div class="firma-nombre">${instructor_nombre || 'Néstor Daniel Reyes Díaz'}</div>
        <div class="firma-cargo">Instructor</div>
        <div class="firma-rfc">${instructor_rfc || 'REDN-770428-433-0005'}</div>
      </div>
      <div class="firma">
        <div class="firma-img-wrap"><img src="${FIRMA_MIRNA}" class="firma-img-m"/></div>
        <div class="firma-nombre">${director_nombre || 'Mirna Rosas Delgado'}</div>
        <div class="firma-cargo">Dirección</div>
      </div>
    </div>
    <div class="datos">
      <div class="dato-row"><span class="dato-label">IDúnico*:</span><span class="dato-valor">${id_unico}</span></div>
      <div class="dato-row"><span class="dato-label">Impartido en:</span><span class="dato-valor">${lugar}</span></div>
      <div class="dato-row"><span class="dato-label">Duración (equivalente):</span><span class="dato-valor">${duracion} Hrs</span></div>
      <div class="dato-row"><span class="dato-label">Fecha:</span><span class="dato-valor">${fechaFormateada}</span></div>
    </div>
  </div>
  <div class="pie">HCD-F-16 Rev2026</div>
</div>
<script>
  function fitTexto(sel, maxPt, minPt){
    var el = document.querySelector(sel);
    if(!el || !el.parentElement) return;
    el.style.whiteSpace = 'nowrap';
    var avail = el.parentElement.clientWidth - 24;
    var s = maxPt, guard = 0;
    el.style.fontSize = s + 'pt';
    while(el.offsetWidth > avail && s > minPt && guard < 300){ s -= 0.5; el.style.fontSize = s + 'pt'; guard++; }
  }
  function ajustarCert(){
    fitTexto('.nombre', 54, 22);
    fitTexto('.curso-nombre', 19, 10);
  }
  window.onload = () => {
    if (document.fonts && document.fonts.ready) {
      document.fonts.ready.then(() => { ajustarCert(); setTimeout(() => window.print(), 300); });
    } else { setTimeout(() => { ajustarCert(); window.print(); }, 600); }
  };
</script>
</body>
</html>`
  ventana.document.write(html)
  ventana.document.close()
}

export async function generarYAbrirCertificado(cert) {
  const qr = await generarQRBase64(cert.id_unico)
  abrirCertificadoParaImprimir({ cert, qrBase64: qr })
}
